import sqlite3
from getpass import getpass

def validate_user(username, password):
    conn = sqlite3.connect('legacy_database.db')  # connect to the legacy database
    cursor = conn.cursor()
    
    query = "SELECT * FROM users WHERE username=? AND password=?"
    cursor.execute(query, (username, password))
    
    user = cursor.fetchone()  # get first record or None if no records found
    
    if user:
        print("Access granted")
    else:
        print("Invalid credentials")
        
def main():
    username = input('Enter your username: ')
    password = getpass('Enter your password: ')  # use getpass to hide password input
    
    validate_user(username, password)

if __name__ == "__main__":
    main()